    fastio;

    long long n;
    cin >> n;

    int cnt = 0;
    int arr[2] = {2, 3};

    while (n != 1) {
        if (n % arr[cnt] != 0) {

            if (cnt) {
                cout << "No" << endl;
                return 0;
            }
            cnt++;
        } else
            n /= arr[cnt];
    }

    cout << "Yes" << endl;

